
import { Trophy, Music, Award, TrendingUp, Calendar, ArrowRight } from 'lucide-react'
import { getTodasAulas } from '@/src/lib/supabase/queries/aulas';
import { getInstrumentos } from '@/src/lib/supabase/queries/instrumentos';
import Link from 'next/link';

export default async function AlunoDashboard() {
  // Buscar dados reais em paralelo
  const [aulas, instrumentos] = await Promise.all([
    getTodasAulas(),
    getInstrumentos()
  ]);

  // Simulação de métricas (já que tabelas de progresso do usuário podem estar vazias user-specific)
  const totalAulas = aulas.length;
  const totalInstrumentos = instrumentos.length;
  const nivelAtual = 1; // Placeholder
  const conquistas = 0; // Placeholder

  // Pegar próximas 3 aulas (simuladas como as primeiras, já que não temos o state de progresso aqui ainda)
  const proximasAulas = aulas.slice(0, 3);

  const stats = [
    { name: 'Nível Atual', value: `Alpha ${nivelAtual}`, icon: TrendingUp, color: 'bg-purple-500' },
    { name: 'Aulas Disponíveis', value: totalAulas.toString(), icon: Calendar, color: 'bg-blue-500' },
    { name: 'Instrumentos', value: totalInstrumentos.toString(), icon: Music, color: 'bg-orange-500' },
    { name: 'Conquistas', value: conquistas.toString(), icon: Trophy, color: 'bg-yellow-500' },
  ]

  return (
    <div className="p-6 lg:p-8 space-y-8">
      <div className="flex flex-col md:flex-row justify-between items-start md:items-end gap-4">
        <div>
          <h1 className="text-3xl font-bold text-gray-900">Olá, Aluno! 👋</h1>
          <p className="text-gray-600 mt-2">Pronto para continuar sua jornada musical hoje?</p>
        </div>
        <div className="text-right hidden md:block">
          <p className="text-sm text-gray-500">Próximo Show Final</p>
          <p className="text-lg font-bold text-red-600">20 de Dezembro</p>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
        {stats.map((stat) => {
          const Icon = stat.icon
          return (
            <div key={stat.name} className="bg-white rounded-xl shadow-sm p-6 border border-gray-100 flex items-center justify-between hover:shadow-md transition-shadow">
              <div>
                <p className="text-sm font-medium text-gray-500">{stat.name}</p>
                <p className="text-2xl font-bold text-gray-900 mt-1">{stat.value}</p>
              </div>
              <div className={`${stat.color} p-3 rounded-lg shadow-sm`}>
                <Icon className="w-6 h-6 text-white" />
              </div>
            </div>
          )
        })}
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Próximas Aulas */}
        <div className="lg:col-span-2 bg-white rounded-xl shadow-sm border border-gray-200 overflow-hidden">
          <div className="p-6 border-b border-gray-100 flex justify-between items-center">
            <h2 className="text-xl font-bold text-gray-900">Sua Trilha de Aprendizado</h2>
            <Link href="/alunos/aulas" className="text-sm text-blue-600 hover:text-blue-700 font-medium">
              Ver todas
            </Link>
          </div>
          <div className="divide-y divide-gray-100">
            {proximasAulas.length > 0 ? (
              proximasAulas.map((aula) => (
                <div key={aula.id} className="p-6 hover:bg-gray-50 transition-colors flex gap-4 items-center">
                  <div className="flex-shrink-0 w-12 h-12 bg-blue-100 text-blue-600 rounded-full flex items-center justify-center font-bold text-lg">
                    {aula.numero}
                  </div>
                  <div className="flex-1">
                    <h3 className="font-semibold text-gray-900">{aula.titulo}</h3>
                    <p className="text-sm text-gray-500 line-clamp-1">{aula.objetivo_didatico}</p>
                  </div>
                  <div className="hidden sm:block text-right">
                    <span className="inline-block px-2 py-1 bg-gray-100 text-gray-600 text-xs rounded-md capitalize">
                      {aula.formato}
                    </span>
                  </div>
                  <Link
                    href="/alunos/aulas"
                    className="p-2 text-gray-400 hover:text-blue-600 hover:bg-blue-50 rounded-full transition-colors"
                  >
                    <ArrowRight className="w-5 h-5" />
                  </Link>
                </div>
              ))
            ) : (
              <div className="p-8 text-center text-gray-500">
                Nenhuma aula disponível no momento.
              </div>
            )}
          </div>
        </div>

        {/* Instrumentos Destaque */}
        <div className="bg-gradient-to-br from-orange-500 to-red-600 rounded-xl shadow-lg text-white p-6 flex flex-col">
          <div className="flex items-center gap-3 mb-6">
            <Music className="w-8 h-8" />
            <h2 className="text-xl font-bold">Explore Instrumentos</h2>
          </div>
          <p className="text-orange-100 mb-8 flex-1">
            Descubra novos sons e histórias na nossa biblioteca completa de instrumentos.
          </p>
          <div className="space-y-4">
            {instrumentos.slice(0, 3).map(inst => (
              <Link key={inst.id} href={`/alunos/instrumentos/${inst.id}`} className="block bg-white/10 hover:bg-white/20 p-3 rounded-lg transition-colors flex justify-between items-center backdrop-blur-sm">
                <span className="font-medium text-sm">{inst.nome}</span>
                <ArrowRight className="w-4 h-4 text-orange-200" />
              </Link>
            ))}
            <Link
              href="/alunos/instrumentos"
              className="block w-full text-center py-3 bg-white text-orange-600 font-bold rounded-lg hover:bg-orange-50 transition-colors mt-4"
            >
              Ver Biblioteca Completa
            </Link>
          </div>
        </div>
      </div>
    </div>
  )
}
